6027 std::optional<const SCEV *>
6028 ScalarEvolution::createNodeForSelectOrPHIInstWithICmpInstCond(Type *Ty,
6029                                                               ICmpInst *Cond,
6030                                                               Value *TrueVal,
6031                                                               Value *FalseVal) {
6032   // Try to match some simple smax or umax patterns.
6033   auto *ICI = Cond;
6034 
6035   Value *LHS = ICI->getOperand(0);
6036   Value *RHS = ICI->getOperand(1);
6037 
6038   switch (ICI->getPredicate()) {
6039   case ICmpInst::ICMP_SLT:
6040   case ICmpInst::ICMP_SLE:
6041   case ICmpInst::ICMP_ULT:
6042   case ICmpInst::ICMP_ULE:
6043     std::swap(LHS, RHS);
6044     [[fallthrough]];
6045   case ICmpInst::ICMP_SGT:
6046   case ICmpInst::ICMP_SGE:
6047   case ICmpInst::ICMP_UGT:
6048   case ICmpInst::ICMP_UGE:
6049     // a > b ? a+x : b+x  ->  max(a, b)+x
6050     // a > b ? b+x : a+x  ->  min(a, b)+x
6051     if (getTypeSizeInBits(LHS->getType()) <= getTypeSizeInBits(Ty)) {
6052       bool Signed = ICI->isSigned();
6053       const SCEV *LA = getSCEV(TrueVal);
6054       const SCEV *RA = getSCEV(FalseVal);
6055       const SCEV *LS = getSCEV(LHS);
6056       const SCEV *RS = getSCEV(RHS);
6057       if (LA->getType()->isPointerTy()) {
6058         // FIXME: Handle cases where LS/RS are pointers not equal to LA/RA.
6059         // Need to make sure we can't produce weird expressions involving
6060         // negated pointers.
6061         if (LA == LS && RA == RS)
6062           return Signed ? getSMaxExpr(LS, RS) : getUMaxExpr(LS, RS);
6063         if (LA == RS && RA == LS)
6064           return Signed ? getSMinExpr(LS, RS) : getUMinExpr(LS, RS);
6065       }
6066       auto CoerceOperand = [&](const SCEV *Op) -> const SCEV * {
6067         if (Op->getType()->isPointerTy()) {
6068           Op = getLosslessPtrToIntExpr(Op);
6069           if (isa<SCEVCouldNotCompute>(Op))
6070             return Op;
6071         }
6072         if (Signed)
6073           Op = getNoopOrSignExtend(Op, Ty);
6074         else
6075           Op = getNoopOrZeroExtend(Op, Ty);
6076         return Op;
6077       };
6078       LS = CoerceOperand(LS);
6079       RS = CoerceOperand(RS);
6080       if (isa<SCEVCouldNotCompute>(LS) || isa<SCEVCouldNotCompute>(RS))
6081         break;
6082       const SCEV *LDiff = getMinusSCEV(LA, LS);
6083       const SCEV *RDiff = getMinusSCEV(RA, RS);
6084       if (LDiff == RDiff)
6085         return getAddExpr(Signed ? getSMaxExpr(LS, RS) : getUMaxExpr(LS, RS),
6086                           LDiff);
6087       LDiff = getMinusSCEV(LA, RS);
6088       RDiff = getMinusSCEV(RA, LS);
6089       if (LDiff == RDiff)
6090         return getAddExpr(Signed ? getSMinExpr(LS, RS) : getUMinExpr(LS, RS),
6091                           LDiff);
6092     }
6093     break;
6094   case ICmpInst::ICMP_NE:
6095     // x != 0 ? x+y : C+y  ->  x == 0 ? C+y : x+y
6096     std::swap(TrueVal, FalseVal);
6097     [[fallthrough]];
6098   case ICmpInst::ICMP_EQ:
6099     // x == 0 ? C+y : x+y  ->  umax(x, C)+y   iff C u<= 1
6100     if (getTypeSizeInBits(LHS->getType()) <= getTypeSizeInBits(Ty) &&
6101         isa<ConstantInt>(RHS) && cast<ConstantInt>(RHS)->isZero()) {
6102       const SCEV *X = getNoopOrZeroExtend(getSCEV(LHS), Ty);
6103       const SCEV *TrueValExpr = getSCEV(TrueVal);    // C+y
6104       const SCEV *FalseValExpr = getSCEV(FalseVal);  // x+y
6105       const SCEV *Y = getMinusSCEV(FalseValExpr, X); // y = (x+y)-x
6106       const SCEV *C = getMinusSCEV(TrueValExpr, Y);  // C = (C+y)-y
6107       if (isa<SCEVConstant>(C) && cast<SCEVConstant>(C)->getAPInt().ule(1))
6108         return getAddExpr(getUMaxExpr(X, C), Y);
6109     }
6110     // x == 0 ? 0 : umin    (..., x, ...)  ->  umin_seq(x, umin    (...))
6111     // x == 0 ? 0 : umin_seq(..., x, ...)  ->  umin_seq(x, umin_seq(...))
6112     // x == 0 ? 0 : umin    (..., umin_seq(..., x, ...), ...)
6113     //                    ->  umin_seq(x, umin (..., umin_seq(...), ...))
6114     if (isa<ConstantInt>(RHS) && cast<ConstantInt>(RHS)->isZero() &&
6115         isa<ConstantInt>(TrueVal) && cast<ConstantInt>(TrueVal)->isZero()) {
6116       const SCEV *X = getSCEV(LHS);
6117       while (auto *ZExt = dyn_cast<SCEVZeroExtendExpr>(X))
6118         X = ZExt->getOperand();
6119       if (getTypeSizeInBits(X->getType()) <= getTypeSizeInBits(Ty)) {
6120         const SCEV *FalseValExpr = getSCEV(FalseVal);
6121         if (SCEVMinMaxExprContains(FalseValExpr, X, scSequentialUMinExpr))
6122           return getUMinExpr(getNoopOrZeroExtend(X, Ty), FalseValExpr,
6123                              /*Sequential=*/true);
6124       }
6125     }
6126     break;
6127   default:
6128     break;
6129   }
6130 
6131   return std::nullopt;
6132 }
