6134 static std::optional<const SCEV *>
6135 createNodeForSelectViaUMinSeq(ScalarEvolution *SE, const SCEV *CondExpr,
6136                               const SCEV *TrueExpr, const SCEV *FalseExpr) {
6137   assert(CondExpr->getType()->isIntegerTy(1) &&
6138          TrueExpr->getType() == FalseExpr->getType() &&
6139          TrueExpr->getType()->isIntegerTy(1) &&
6140          "Unexpected operands of a select.");
6141 
6142   // i1 cond ? i1 x : i1 C  -->  C + (i1  cond ? (i1 x - i1 C) : i1 0)
6143   //                        -->  C + (umin_seq  cond, x - C)
6144   //
6145   // i1 cond ? i1 C : i1 x  -->  C + (i1  cond ? i1 0 : (i1 x - i1 C))
6146   //                        -->  C + (i1 ~cond ? (i1 x - i1 C) : i1 0)
6147   //                        -->  C + (umin_seq ~cond, x - C)
6148 
6149   // FIXME: while we can't legally model the case where both of the hands
6150   // are fully variable, we only require that the *difference* is constant.
6151   if (!isa<SCEVConstant>(TrueExpr) && !isa<SCEVConstant>(FalseExpr))
6152     return std::nullopt;
6153 
6154   const SCEV *X, *C;
6155   if (isa<SCEVConstant>(TrueExpr)) {
6156     CondExpr = SE->getNotSCEV(CondExpr);
6157     X = FalseExpr;
6158     C = TrueExpr;
6159   } else {
6160     X = TrueExpr;
6161     C = FalseExpr;
6162   }
6163   return SE->getAddExpr(C, SE->getUMinExpr(CondExpr, SE->getMinusSCEV(X, C),
6164                                            /*Sequential=*/true));
6165 }
6166 
6167 static std::optional<const SCEV *>
6168 createNodeForSelectViaUMinSeq(ScalarEvolution *SE, Value *Cond, Value *TrueVal,
6169                               Value *FalseVal) {
6170   if (!isa<ConstantInt>(TrueVal) && !isa<ConstantInt>(FalseVal))
6171     return std::nullopt;
6172 
6173   const auto *SECond = SE->getSCEV(Cond);
6174   const auto *SETrue = SE->getSCEV(TrueVal);
6175   const auto *SEFalse = SE->getSCEV(FalseVal);
6176   return createNodeForSelectViaUMinSeq(SE, SECond, SETrue, SEFalse);
6177 }
