13826     }
13827     return Proper ? ProperlyDominatesBlock : DominatesBlock;
13828   }
13829   case scUnknown:
13830     if (Instruction *I =
13831           dyn_cast<Instruction>(cast<SCEVUnknown>(S)->getValue())) {
