13977 void ScalarEvolution::getReachableBlocks(
13978     SmallPtrSetImpl<BasicBlock *> &Reachable, Function &F) {
13979   SmallVector<BasicBlock *> Worklist;
13980   Worklist.push_back(&F.getEntryBlock());
13981   while (!Worklist.empty()) {
13982     BasicBlock *BB = Worklist.pop_back_val();
13983     if (!Reachable.insert(BB).second)
13984       continue;
13985 
13986     Value *Cond;
13987     BasicBlock *TrueBB, *FalseBB;
13988     if (match(BB->getTerminator(), m_Br(m_Value(Cond), m_BasicBlock(TrueBB),
13989                                         m_BasicBlock(FalseBB)))) {
13990       if (auto *C = dyn_cast<ConstantInt>(Cond)) {
13991         Worklist.push_back(C->isOne() ? TrueBB : FalseBB);
13992         continue;
13993       }
13994 
13995       if (auto *Cmp = dyn_cast<ICmpInst>(Cond)) {
13996         const SCEV *L = getSCEV(Cmp->getOperand(0));
13997         const SCEV *R = getSCEV(Cmp->getOperand(1));
13998         if (isKnownPredicateViaConstantRanges(Cmp->getPredicate(), L, R)) {
13999           Worklist.push_back(TrueBB);
14000           continue;
14001         }
14002         if (isKnownPredicateViaConstantRanges(Cmp->getInversePredicate(), L,
14003                                               R)) {
14004           Worklist.push_back(FalseBB);
14005           continue;
14006         }
14007       }
14008     }
14009 
14010     append_range(Worklist, successors(BB));
14011   }
14012 }
